import { resolvePath } from "@typespec/compiler";
import { createLinterRuleTester, createTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { eventCallGraphRule } from "./event-call-graph.rule.js";

/**
 * A tester that includes @typespec/events so that @events unions compile correctly.
 */
const EventsTester = createTester(resolvePath(import.meta.dirname, "../.."), {
  libraries: ["@a10n/blueprint-typespec", "@a10n/typespec-dbml", "@typespec/events"],
})
  .importLibraries()
  .using("State")
  .using("TypeSpec.Events");

// Shared TypeSpec: a @component with @events union and a @worker sub-namespace.
// Component names must end with recognized suffixes (-service, -cli).
const EVENTS_SETUP = `
  @component(#{ type: ComponentType.Service })
  namespace Components.EventService {
    @events
    union LifecycleEvent {
      RunRequested: { id: string };
      RunCompleted: { result: string };
      RunCancelled: { reason: string };
    }

    @worker
    namespace Workers {
    }
  }
`;

describe("event-call-graph rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await EventsTester.createInstance();
    ruleTester = createLinterRuleTester(runner, eventCallGraphRule, "@a10n/blueprint-typespec");
  });

  // ── publishes-op-only ──────────────────────────────────────────────────────
  // NOTE: @publishes has `extern dec publishes(target: Operation, ...)` which means
  // the TypeSpec compiler enforces the Operation-target constraint at the decorator
  // declaration level. The rule cannot emit publishesOpOnly because the program never
  // reaches rule evaluation when @publishes is placed on a non-Operation — the compiler
  // rejects it first. This test documents that placing @publishes on a valid Operation
  // (and only that) compiles without a rule-level diagnostic for the target kind.
  // T015_05: "@publishes on a model emits publishes-op-only" is compiler-enforced and
  // cannot be exercised at the rule level. The describe block below documents this behaviour.
  describe("publishes-op-only (compiler-enforced)", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_event_call_graph
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_04
    it("T015_04: @publishes on an op — no rule-level publishesOpOnly diagnostic", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested}.")
          op start_run_op_only(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_op_only(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toBeValid();
    });
  });

  // ── publishes-no-subscriber ───────────────────────────────────────────────

  describe("publishes-no-subscriber", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_12
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_event_call_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_has_subscriber:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_has_subscriber:must
    it("T015_12: every published event has at least one subscriber — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} when the run starts.")
          op start_run(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op init_run(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_13
    it("T015_13: published event with no subscriber — emits publishesHasSubscriber", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} when the run starts.")
          op start_run(): void;
        `)
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/event-call-graph",
            message: /RunRequested.*no @subscribes/,
          },
        ]);
    });
  });

  // ── worker-input-variant ───────────────────────────────────────────────────

  describe("worker-input-variant", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_14
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_event_call_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.worker_input_variant:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.EventCallGraph.worker_input_variant:must
    it("T015_14: worker op input typed as @events variant — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} when the run starts.")
          op start_run_a(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_run(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_15
    it("T015_15: worker op input typed as a non-@events model — emits workerInputVariant", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          model RandomPayload { id: string; }

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.ConsumerService {
            @subscribes
            op handle_random(event: RandomPayload): void;
          }
        `)
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/event-call-graph",
            message: /handle_random.*RandomPayload.*not a variant/,
          },
        ]);
    });
  });

  // ── publishes-absent-pure ──────────────────────────────────────────────────

  describe("publishes-absent-pure", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_08
    it("T015_08: op with no @publishes and @doc with no event refs — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @doc("Performs a pure computation with no event side effects.")
          op pure_helper(): void;
        `)
        .toBeValid();
    });

    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_event_call_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_absent_pure:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_absent_pure:must
    it("op with @publishes and @doc referencing the published event — no publishes-absent-pure", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} when the run starts.")
          op start_run_b(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_run_b(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_09
    it("T015_09: op with @publishes and @doc with no event refs — emits publishesAbsentPure", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Performs a pure transformation with no side effects.")
          op pure_helper_c(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_for_pure(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/event-call-graph",
            message: /pure_helper_c.*carries @publishes.*no event emissions/,
          },
        ]);
    });

    it("op with @publishes but no @doc at all — emits publishesAbsentPure", async () => {
      // T015_09 proxy: an op that claims an emission via @publishes but has no @doc
      // at all cannot prove the emission is documented — conservative violation.
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          op pure_helper_nodoc(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_for_nodoc(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/event-call-graph",
            message: /pure_helper_nodoc.*carries @publishes.*no event emissions/,
          },
        ]);
    });
  });

  // ── publishes-incomplete ──────────────────────────────────────────────────

  describe("publishes-incomplete", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_06
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_event_call_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_lists_all:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.EventCallGraph.publishes_lists_all:must
    it("T015_06: op declaring all emitted events in @publishes — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @publishes(Components.EventService.LifecycleEvent.RunCompleted)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} and {@Components.EventService.LifecycleEvent.RunCompleted}.")
          op process_run_d(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_req(event: Components.EventService.LifecycleEvent.RunRequested): void;
            @subscribes
            op handle_done(event: Components.EventService.LifecycleEvent.RunCompleted): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_07
    it("T015_07: op with @doc event ref missing from @publishes — emits publishesListsAll", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} and {@Components.EventService.LifecycleEvent.RunCompleted}.")
          op process_run_e(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_req_e(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/event-call-graph",
            message: /process_run_e.*RunCompleted.*not declared in @publishes/,
          },
        ]);
    });
  });

  // ── subscribes-incomplete ─────────────────────────────────────────────────

  describe("subscribes-incomplete", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_10
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_event_call_graph:Products.A10nBlueprintEngine.Features.EventCallGraph.subscribes_lists_all:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.EventCallGraph.subscribes_lists_all:must
    it("T015_10: worker op input type matches all @doc event refs — no diagnostic", async () => {
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} when the run starts.")
          op start_run_f(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            @doc("Handles {@Components.EventService.LifecycleEvent.RunRequested} events.")
            op handle_run_f(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T015.T015_11
    it("T015_11: worker op @doc refs event not in input type — emits subscribesListsAll", async () => {
      // handle_run_g only subscribes to RunRequested in its input type
      // but its @doc mentions RunCancelled too — the rule flags it.
      // A separate op subscribes to RunCancelled to avoid publishesHasSubscriber noise.
      await ruleTester
        .expect(`
          ${EVENTS_SETUP}

          @publishes(Components.EventService.LifecycleEvent.RunRequested)
          @publishes(Components.EventService.LifecycleEvent.RunCancelled)
          @doc("Emits {@Components.EventService.LifecycleEvent.RunRequested} and {@Components.EventService.LifecycleEvent.RunCancelled}.")
          op start_run_g(): void;

          @component(#{ type: ComponentType.Service })
          @worker
          namespace Components.WorkerService {
            @subscribes
            op handle_cancel_g(event: Components.EventService.LifecycleEvent.RunCancelled): void;
            @subscribes
            @doc("Handles {@Components.EventService.LifecycleEvent.RunRequested} and {@Components.EventService.LifecycleEvent.RunCancelled} events.")
            op handle_run_g(event: Components.EventService.LifecycleEvent.RunRequested): void;
          }
        `)
        .toEmitDiagnostics([
          {
            code: "@a10n/blueprint-typespec/event-call-graph",
            message: /handle_run_g.*RunCancelled.*not matched/,
          },
        ]);
    });
  });
});
